import java.util.Arrays;

public class Solution {
    public static long solve(long[] piles) {
        int n = piles.length;
        Arrays.sort(piles);
        long sum = 0;
        int groups = n / 3;
        for (int i = 0; i < groups; i++) {
            int pos = n - 2 - 2 * i;
            sum += piles[pos];
        }
        return sum;
    }
}
